/**
 * Stage the locally-built ESP32-classic (Xtensa) toolchain + the minimized arduino-esp32 (classic)
 * SDK header pack into static assets the browser build worker self-hosts (no server compile,
 * invariant I8). Mirrors make-c3-fixtures.mjs. The output is GITIGNORED + regenerated by
 * `pnpm esp32-classic-fixtures`; the Xtensa e2e / run skips if it's absent.
 *
 * Output (packages/app/public/esp32-classic-toolchain/):
 *   clang.mjs, lld.mjs        — the cross-built Xtensa clang + ld.lld WASM ES modules (SINGLE_FILE)
 *   esp32-classic-sdk.json    — { files: [{path, b64}], runtime: b64, linker: b64 } — the header
 *                               closure + the 2 @response files + the architecture-neutral Arduino
 *                               HAL sim runtime + the `.literal`-before-`.text` flat linker script
 *
 * NOTE the Xtensa clang/lld live under ci/toolchain-builder/esp32-classic/build/wasm-out, but the SDK
 * (arduino-data) is the SHARED tree under ci/toolchain-builder/esp32/build — same as the C3 fixtures.
 */
import {
  existsSync,
  mkdirSync,
  readFileSync,
  writeFileSync,
  copyFileSync,
  readdirSync,
} from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createHash } from 'node:crypto';

const sha256 = (buf) => createHash('sha256').update(buf).digest('hex'); // integrity pin (AUD-013)

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const SDK_BUILD = join(root, 'ci', 'toolchain-builder', 'esp32', 'build'); // shared arduino-data
const WASM_OUT = join(root, 'ci', 'toolchain-builder', 'esp32-classic', 'build', 'wasm-out'); // Xtensa clang/lld
// WiFi manifest (superset): WiFi/Network headers + their C++ stdlib closure, so an ESP32-classic sketch
// with `#include <WiFi.h>` compiles client-side (I8). Headers are already staged in the shared arduino-data.
const MANIFEST = join(
  root,
  'packages',
  'toolchain-loader',
  'src',
  '__fixtures__',
  'esp32-classic-wifi-sdk-manifest.txt',
);
const RUNTIME = join(
  root,
  'packages',
  'emulators',
  'src',
  'sim-runtime',
  'esp32c3-arduino-sim.cpp',
);
const LINKER = join(root, 'packages', 'emulators', 'src', 'sim-runtime', 'xtensa-flat.ld');
const DST = join(root, 'packages', 'app', 'public', 'esp32-classic-toolchain');

// @-response files referenced by the compile flags but NOT in the #include closure manifest.
const LIBS = 'arduino-data/packages/esp32/tools/esp32-libs/3.3.10';
const RESPONSE_FILES = [`${LIBS}/flags/defines`, `${LIBS}/flags/includes`];

const clang = join(WASM_OUT, 'clang.mjs');
const lld = join(WASM_OUT, 'lld.mjs');
if (!existsSync(clang) || !existsSync(lld) || !existsSync(MANIFEST)) {
  console.error(
    'Xtensa toolchain not built (ci/toolchain-builder/esp32-classic/build/wasm-out/{clang,lld}.mjs missing).',
  );
  console.error(
    'Run the [CI/HUMAN] toolchain build first (see ci/toolchain-builder/).',
  );
  process.exit(0); // soft-skip — same as the gate test
}

mkdirSync(DST, { recursive: true });
copyFileSync(clang, join(DST, 'clang.mjs'));
copyFileSync(lld, join(DST, 'lld.mjs'));

const rels = readFileSync(MANIFEST, 'utf8').split('\n').filter(Boolean).concat(RESPONSE_FILES);
const files = [];
let total = 0;
for (const rel of rels) {
  const abs = join(SDK_BUILD, rel);
  if (!existsSync(abs)) {
    console.warn(`  skip (missing): ${rel}`);
    continue;
  }
  const bytes = readFileSync(abs);
  total += bytes.length;
  files.push({ path: rel, b64: bytes.toString('base64') });
}
// Sparklab firmware helper headers — mounted at <root>/spark (see make-c3-fixtures); `-I<root>/spark`.
const SPARK = join(root, 'packages', 'emulators', 'src', '__fixtures__');
const sparkHeaders = [
  ['SparkNet', 'SparkNet.h'],
  ...readdirSync(join(SPARK, 'SparkBlynk'))
    .filter((f) => f.endsWith('.h'))
    .map((f) => ['SparkBlynk', f]),
];
for (const [dir, file] of sparkHeaders) {
  const abs = join(SPARK, dir, file);
  if (!existsSync(abs)) continue;
  const bytes = readFileSync(abs);
  total += bytes.length;
  files.push({ path: `spark/${file}`, b64: bytes.toString('base64') });
}
const runtime = readFileSync(RUNTIME).toString('base64');
const linker = readFileSync(LINKER).toString('base64');

// Standard-library archives (Xtensa esp32 multilib — WINDOWED ABI) linked in a group so a sketch/library
// using snprintf/<math>/memcpy/new resolves with its REAL picolibc implementation (mirrors the C3 pack).
// Members are pulled on demand, so a sketch using none keeps the firmware tiny. Paths match the proven set
// in packages/emulators/src/esp32-classic-libc.test.ts (libgcc lives under picolibc/lib/gcc, not lib/gcc).
const GCC = 'arduino-data/packages/esp32/tools/esp-x32/2601';
const ARCHIVE_SRC = [
  ['libc.a', `${GCC}/picolibc/xtensa-esp-elf/lib/esp32/libc.a`],
  ['libm.a', `${GCC}/picolibc/xtensa-esp-elf/lib/esp32/libm.a`],
  ['libgcc.a', `${GCC}/picolibc/lib/gcc/xtensa-esp-elf/14.2.0/esp32/libgcc.a`],
];
const archives = [];
let archTotal = 0;
for (const [name, rel] of ARCHIVE_SRC) {
  const abs = join(SDK_BUILD, rel);
  if (!existsSync(abs)) {
    console.warn(`  skip archive (missing): ${rel}`);
    continue;
  }
  const bytes = readFileSync(abs);
  archTotal += bytes.length;
  archives.push({ name, b64: bytes.toString('base64') });
}

const sdkJson = JSON.stringify({ files, runtime, linker, archives });
writeFileSync(join(DST, 'esp32-classic-sdk.json'), sdkJson);
// Integrity manifest (AUD-013): pin every self-hosted asset.
writeFileSync(
  join(DST, 'integrity.json'),
  JSON.stringify({
    'clang.mjs': sha256(readFileSync(join(DST, 'clang.mjs'))),
    'lld.mjs': sha256(readFileSync(join(DST, 'lld.mjs'))),
    'esp32-classic-sdk.json': sha256(sdkJson),
  }),
);
const mb = (n) => (n / 1048576).toFixed(1);
console.log(`ESP32-classic (Xtensa) fixtures → ${DST}`);
console.log(
  `  clang.mjs (${mb(readFileSync(clang).length)} MB) + lld.mjs (${mb(readFileSync(lld).length)} MB)`,
);
console.log(
  `  esp32-classic-sdk.json: ${files.length} SDK files (${mb(total)} MB raw) + runtime HAL + linker script + ${archives.length} stdlib archives (${mb(archTotal)} MB)`,
);
